"""
Parameterized generator for GH303_simili-bot_61.

Source PR:    https://github.com/similigh/simili-bot/pull/61
Source Issue: https://github.com/similigh/simili-bot/issues/59

Seed varies: renames 'action' identifier with suffix across seeds.

Bug: pre-PR state of workspace files contains the bug the PR fixes.
Fix: agent must replicate the PR's changes guided by spec.md.
"""
from __future__ import annotations

import os
from generators.base import TaskGenerator, GeneratedTask


class Generator(TaskGenerator):
    task_id = 'GH303_simili-bot_61'
    domain = "Real-World GitHub"
    difficulty = "medium"
    languages = ["python"]

    def generate(self, seed: int) -> GeneratedTask:
        tasks_dir = os.path.join(
            os.path.dirname(__file__), "..", "tasks", 'GH303_simili-bot_61'
        )
        with open(os.path.join(tasks_dir, "spec.md")) as f:
            spec_md = f.read()
        with open(os.path.join(tasks_dir, "brief.md")) as f:
            brief_md = f.read()

        files = self._base_workspace()
        # Apply seed-based renaming to prevent direct memorization
        suffixes = ["", "_alt", "_impl"]
        suffix = suffixes[seed % len(suffixes)]
        if suffix:
            for fpath in list(files.keys()):
                files[fpath] = files[fpath].replace('action', 'action' + suffix)
        # Deep parameterization — consistent cross-seed variation
        from generators.gh_deep_param import deep_rename_symbols, add_realistic_noise
        files = deep_rename_symbols(files, seed, strategy="mixed")
        files = add_realistic_noise(files, seed, noise_level=0.15)
        return GeneratedTask(
            task_id='GH303_simili-bot_61',
            seed=seed,
            spec_md=spec_md,
            brief_md=brief_md,
            expected={
                "seed": seed,
                "repo": 'similigh/simili-bot',
                "pr_number": 61,
                "bug_fixed": True,
            },
            workspace_files=files,
            metadata={
                "difficulty": "medium",
                "category": "Real-World GitHub",
                "source_pr": "https://github.com/similigh/simili-bot/pull/61",
            },
        )

    def _base_workspace(self) -> dict[str, str]:
        """Return the pre-PR (buggy) workspace files."""
        return {
            'cmd/simili/commands/index.go': '// Author: Kaviru Hapuarachchi\n// GitHub: https://github.com/Kavirubc\n// Created: 2026-02-02\n// Last Modified: 2026-02-13\n\npackage commands\n\nimport (\n\t"context"\n\t"fmt"\n\t"log"\n\t"os"\n\t"strings"\n\t"sync"\n\t"time"\n\n\t"github.com/google/go-github/v60/github"\n\t"github.com/google/uuid"\n\tsimiliConfig "github.com/similigh/simili-bot/internal/core/config"\n\t"github.com/similigh/simili-bot/internal/integrations/gemini"\n\tsimiliGithub "github.com/similigh/simili-bot/internal/integrations/github"\n\t"github.com/similigh/simili-bot/internal/integrations/qdrant"\n\t"github.com/similigh/simili-bot/internal/utils/text"\n\t"github.com/spf13/cobra"\n)\n\nvar (\n\tindexRepo       string\n\tindexSince      string // Can be a timestamp (ISO8601) or issue number (int)\n\tindexWorkers    int\n\tindexToken      string\n\tindexDryRun     bool\n\tindexIncludePRs bool\n)\n\ntype Checkpoint struct {\n\tLastProcessedIssue int       `json:"last_processed_issue"`\n\tTimestamp          time.Time `json:"timestamp"`\n}\n\n// indexCmd represents the index command\nvar indexCmd = &cobra.Command{\n\tUse:   "index",\n\tShort: "Bulk index issues into the vector database",\n\tLong: `Index existing issues from a GitHub repository into the Qdrant vector database.\nIt fetches issues, comments, chunks the text, generates embeddings using Gemini,\nand stores them for semantic search.\n\nSupports resuming via a local checkpoint file or --since flag.`,\n\tRun: runIndex,\n}\n\nfunc init() {\n\trootCmd.AddCommand(indexCmd)\n\n\tindexCmd.Flags().StringVar(&indexRepo, "repo", "", "Target repository (owner/name)")\n\tindexCmd.Flags().StringVar(&indexSince, "since", "", "Start indexing from this issue number or timestamp")\n\tindexCmd.Flags().IntVar(&indexWorkers, "workers", 5, "Number of concurrent workers")\n\tindexCmd.Flags().StringVar(&indexToken, "token", "", "GitHub token (optional, defaults to GITHUB_TOKEN env var)")\n\tindexCmd.Flags().BoolVar(&indexDryRun, "dry-run", false, "Simulate indexing without writing to DB")\n\tindexCmd.Flags().BoolVar(&indexIncludePRs, "include-prs", true, "Include pull requests in indexing")\n\n\tif err := indexCmd.MarkFlagRequired("repo"); err != nil {\n\t\tlog.Fatalf("Failed to mark repo flag as required: %v", err)\n\t}\n}\n\nfunc runIndex(cmd *cobra.Command, args []string) {\n\tctx := context.Background()\n\n\t// 1. Load Config\n\tcfgPath := similiConfig.FindConfigPath(cfgFile)\n\tif cfgPath == "" {\n\t\tlog.Fatalf("Config file not found. Please verify your setup.")\n\t}\n\tcfg, err := similiConfig.Load(cfgPath)\n\tif err != nil {\n\t\tlog.Fatalf("Failed to load config: %v", err)\n\t}\n\n\t// 2. Auth & Clients\n\ttoken := indexToken\n\tif token == "" {\n\t\ttoken = os.Getenv("GITHUB_TOKEN")\n\t}\n\tif token == "" {\n\t\tlog.Fatal("GitHub token is required (use --token or GITHUB_TOKEN env var)")\n\t}\n\n\tghClient := similiGithub.NewClient(ctx, token)\n\n\tgeminiClient, err := gemini.NewEmbedder(cfg.Embedding.APIKey, cfg.Embedding.Model)\n\tif err != nil {\n\t\tlog.Fatalf("Failed to init Gemini: %v", err)\n\t}\n\tdefer geminiClient.Close()\n\n\tvar qdrantClient *qdrant.Client\n\tif !indexDryRun {\n\t\tqdrantClient, err = qdrant.NewClient(cfg.Qdrant.URL, cfg.Qdrant.APIKey)\n\t\tif err != nil {\n\t\t\tlog.Fatalf("Failed to init Qdrant: %v", err)\n\t\t}\n\t\tdefer qdrantClient.Close()\n\n\t\t// Ensure collection exists\n\t\terr = qdrantClient.CreateCollection(ctx, cfg.Qdrant.Collection, cfg.Embedding.Dimensions)\n\t\tif err != nil {\n\t\t\tlog.Fatalf("Failed to create/verify collection: %v", err)\n\t\t}\n\t}\n\n\t// 3. Parse Repo\n\tparts := strings.Split(indexRepo, "/")\n\tif len(parts) != 2 {\n\t\tlog.Fatalf("Invalid repo format: %s (expected owner/name)", indexRepo)\n\t}\n\torg, repoName := parts[0], parts[1]\n\n\t// 4. Determine Start Point (Since)\n\t// Checkpoint logic omitted for simplicity in v0.1.0 as standard pagination handles most cases.\n\t// Users can rely on --since for updates.\n\n\tlog.Printf("Starting indexing for %s/%s with %d workers...", org, repoName, indexWorkers)\n\n\t// Fetch loop\n\tpage := 1\n\tsplitter := text.NewRecursiveCharacterSplitter()\n\n\t// Job channel\n\ttype Job struct {\n\t\tIssue *github.Issue\n\t}\n\tjobs := make(chan Job, indexWorkers)\n\tvar wg sync.WaitGroup\n\n\t// Start Workers\n\tfor i := 0; i < indexWorkers; i++ {\n\t\twg.Add(1)\n\t\tgo func(id int) {\n\t\t\tdefer wg.Done()\n\t\t\tfor job := range jobs {\n\t\t\t\tprocessIssue(ctx, id, job.Issue, ghClient, geminiClient, qdrantClient, splitter, cfg.Qdrant.Collection, org, repoName, indexDryRun)\n\t\t\t}\n\t\t}(i)\n\t}\n\n\t// Issue Producer\n\topts := &github.IssueListByRepoOptions{\n\t\tState:       "all",\n\t\tSort:        "created",\n\t\tDirection:   "asc",\n\t\tListOptions: github.ListOptions{PerPage: 100},\n\t}\n\n\tif indexSince != "" {\n\t\tt, err := time.Parse(time.RFC3339, indexSince)\n\t\tif err == nil {\n\t\t\topts.Since = t\n\t\t} else {\n\t\t\tlog.Printf("Warning: Could not parse --since as ISO8601, ignoring (fetching all)")\n\t\t}\n\t}\n\n\tfor {\n\t\topts.Page = page\n\t\tissues, resp, err := ghClient.ListIssues(ctx, org, repoName, opts)\n\t\tif err != nil {\n\t\t\tlog.Printf("Error listing issues page %d: %v", page, err)\n\t\t\tbreak // Stop producer\n\t\t}\n\n\t\tif len(issues) == 0 {\n\t\t\tbreak\n\t\t}\n\n\t\tlog.Printf("Fetched page %d (%d issues)", page, len(issues))\n\n\t\tfor _, issue := range issues {\n\t\t\tif !indexIncludePRs && issue.IsPullRequest() {\n\t\t\t\tcontinue\n\t\t\t}\n\t\t\tjobs <- Job{Issue: issue}\n\t\t}\n\n\t\tif resp.NextPage == 0 {\n\t\t\tbreak\n\t\t}\n\t\tpage = resp.NextPage\n\t}\n\n\tclose(jobs)\n\twg.Wait()\n\tlog.Println("Indexing complete.")\n}\n\nfunc processIssue(ctx context.Context, workerID int, issue *github.Issue, gh *similiGithub.Client, em *gemini.Embedder, qd *qdrant.Client, splitter *text.RecursiveCharacterSplitter, collection, org, repo string, dryRun bool) {\n\t// 1. Fetch Comments (with pagination)\n\tvar allComments []*github.IssueComment\n\tpage := 1\n\tfor {\n\t\tcomments, resp, err := gh.ListComments(ctx, org, repo, issue.GetNumber(), &github.IssueListCommentsOptions{\n\t\t\tListOptions: github.ListOptions{PerPage: 100, Page: page},\n\t\t})\n\t\tif err != nil {\n\t\t\tlog.Printf("[Worker %d] Error fetching comments for #%d: %v", workerID, issue.GetNumber(), err)\n\t\t\treturn\n\t\t}\n\t\tallComments = append(allComments, comments...)\n\t\tif resp == nil || resp.NextPage == 0 {\n\t\t\tbreak\n\t\t}\n\t\tpage = resp.NextPage\n\t}\n\n\t// 2. Aggregate Text\n\tcomments := make([]text.Comment, 0, len(allComments))\n\tfor _, c := range allComments {\n\t\tbody := strings.TrimSpace(c.GetBody())\n\t\tif body == "" {\n\t\t\tcontinue\n\t\t}\n\t\tauthor := "deleted-user"\n\t\tif c.User != nil {\n\t\t\tauthor = c.User.GetLogin()\n\t\t}\n\t\tcomments = append(comments, text.Comment{Author: author, Body: body})\n\t}\n\tfullText := text.BuildEmbeddingContent(issue.GetTitle(), issue.GetBody(), comments)\n\n\t// 3. Chunk\n\tchunks := splitter.SplitText(fullText)\n\n\t// 4. Embed\n\tembeddings, err := em.EmbedBatch(ctx, chunks)\n\tif err != nil {\n\t\tlog.Printf("[Worker %d] Error embedding #%d: %v", workerID, issue.GetNumber(), err)\n\t\treturn\n\t}\n\n\t// 5. Upsert\n\tif dryRun {\n\t\tlog.Printf("[DryRun] Would upsert #%d (%d chunks)", issue.GetNumber(), len(chunks))\n\t\treturn\n\t}\n\n\titemType := "issue"\n\tif issue.IsPullRequest() {\n\t\titemType = "pull_request"\n\t}\n\n\tpoints := make([]*qdrant.Point, len(chunks))\n\tfor i, chunk := range chunks {\n\t\tchunkID := uuid.NewMD5(uuid.NameSpaceURL, fmt.Appendf(nil, "%s/%s#%d-chunk-%d", org, repo, issue.GetNumber(), i)).String()\n\t\tpoints[i] = &qdrant.Point{\n\t\t\tID:     chunkID,\n\t\t\tVector: embeddings[i],\n\t\t\tPayload: map[string]any{\n\t\t\t\t"org":          org,\n\t\t\t\t"repo":         repo,\n\t\t\t\t"issue_number": issue.GetNumber(),\n\t\t\t\t"text":         chunk,\n\t\t\t\t"url":          issue.GetHTMLURL(),\n\t\t\t\t"type":         itemType,\n\t\t\t},\n\t\t}\n\t}\n\n\terr = qd.Upsert(ctx, collection, points)\n\tif err != nil {\n\t\tlog.Printf("[Worker %d] Error upserting #%d: %v", workerID, issue.GetNumber(), err)\n\t} else {\n\t\tlog.Printf("[Worker %d] Indexed #%d", workerID, issue.GetNumber())\n\t}\n}\n',
            'internal/integrations/gemini/prompts.go': '// Author: Kaviru Hapuarachchi\n// GitHub: https://github.com/Kavirubc\n// Created: 2026-02-02\n// Last Modified: 2026-02-05\n\npackage gemini\n\nimport (\n\t"fmt"\n\t"strings"\n)\n\n// truncate limits a string to a maximum length in runes (UTF-8 safe).\nfunc truncate(s string, maxLen int) string {\n\trunes := []rune(s)\n\tif len(runes) <= maxLen {\n\t\treturn s\n\t}\n\treturn string(runes[:maxLen]) + "..."\n}\n\n// indentText indents each non-empty line of text with the given prefix.\nfunc indentText(text string, indent string) string {\n\tlines := strings.Split(text, "\\n")\n\tfor i := range lines {\n\t\tif lines[i] != "" {\n\t\t\tlines[i] = indent + lines[i]\n\t\t}\n\t}\n\treturn strings.Join(lines, "\\n")\n}\n\n// buildTriagePromptJSON creates a prompt for issue triage analysis with JSON output.\nfunc buildTriagePromptJSON(issue *IssueInput) string {\n\treturn fmt.Sprintf(`You are an AI assistant helping with GitHub issue triage. Analyze the following issue and provide your assessment in JSON format.\n\nIssue Details:\n- Title: %s\n- Body: %s\n- Author: %s\n- Current Labels: %s\n\nAnalyze:\n- Is the issue well-described with clear steps to reproduce (for bugs) or clear requirements (for features)?\n- What type of issue is this?\n- Are there any red flags (spam, duplicate, off-topic)?\n\nRespond with valid JSON in this exact format:\n{\n  "quality": "good|needs-improvement|poor",\n  "suggested_labels": ["bug", "enhancement", "documentation", "question"],\n  "reasoning": "Your brief analysis here",\n  "is_duplicate": false,\n  "duplicate_reason": ""\n}\n\nNote: Only set is_duplicate to true if this appears to be a duplicate of an existing issue.`,\n\t\tissue.Title,\n\t\ttruncate(issue.Body, 1000), // Limit body length\n\t\tissue.Author,\n\t\tstrings.Join(issue.Labels, ", "),\n\t)\n}\n\n// buildTriagePrompt creates a prompt for issue triage analysis (legacy format).\n// Deprecated: Use buildTriagePromptJSON for structured output.\nfunc buildTriagePrompt(issue *IssueInput) string {\n\treturn fmt.Sprintf(`You are an AI assistant helping with GitHub issue triage. Analyze the following issue and provide:\n\n1. Quality assessment (good, needs-improvement, or poor)\n2. Suggested labels (bug, enhancement, documentation, question, etc.)\n3. Brief reasoning for your assessment\n\nIssue Details:\n- Title: %s\n- Body: %s\n- Author: %s\n- Current Labels: %s\n\nProvide a concise analysis focusing on:\n- Is the issue well-described with clear steps to reproduce (for bugs) or clear requirements (for features)?\n- What type of issue is this?\n- Are there any red flags (spam, duplicate, off-topic)?\n\nFormat your response as:\nQuality: [good/needs-improvement/poor]\nLabels: [comma-separated list]\nReasoning: [your analysis]`,\n\t\tissue.Title,\n\t\ttruncate(issue.Body, 1000), // Limit body length\n\t\tissue.Author,\n\t\tstrings.Join(issue.Labels, ", "),\n\t)\n}\n\n// buildResponsePrompt creates a prompt for generating a response about similar issues.\nfunc buildResponsePrompt(similar []SimilarIssueInput) string {\n\tvar issueList strings.Builder\n\tfor i, s := range similar {\n\t\tstatus := "open"\n\t\tif s.State == "closed" {\n\t\t\tstatus = "closed"\n\t\t}\n\t\tissueList.WriteString(fmt.Sprintf("%d. #%d: %s (%.0f%% similar, %s)\\n   %s\\n",\n\t\t\ti+1, s.Number, s.Title, s.Similarity*100, status, s.URL))\n\t}\n\n\treturn fmt.Sprintf(`You are an AI assistant helping users find related GitHub issues. \n\nThe following similar issues were found:\n\n%s\n\nGenerate a friendly, helpful comment to inform the user about these similar issues. The comment should:\n- Be concise and professional\n- Mention that these are AI-detected similar issues\n- Encourage the user to check if any of these resolve their question/problem\n- If there are closed issues, mention they might contain solutions\n- Use markdown formatting for links\n\nKeep the response under 200 words.`,\n\t\tissueList.String(),\n\t)\n}\n\n// buildRouteIssuePrompt creates a prompt for repository routing analysis.\nfunc buildRouteIssuePrompt(input *RouteIssueInput) string {\n\tvar repoList strings.Builder\n\thasDefinitions := false\n\n\tfor i, r := range input.Repositories {\n\t\trepoList.WriteString(fmt.Sprintf("%d. %s/%s\\n", i+1, r.Org, r.Repo))\n\n\t\t// Include full definition if available\n\t\tif r.Definition != "" {\n\t\t\thasDefinitions = true\n\t\t\t// Truncate if too long (max 2000 chars per repo to prevent token explosion)\n\t\t\tdefinition := r.Definition\n\t\t\tif len(definition) > 2000 {\n\t\t\t\tdefinition = definition[:2000] + "\\n... (truncated)"\n\t\t\t}\n\t\t\trepoList.WriteString(fmt.Sprintf("   Documentation:\\n%s\\n\\n", indentText(definition, "   ")))\n\t\t} else if r.Description != "" {\n\t\t\t// Fallback to short description from config\n\t\t\trepoList.WriteString(fmt.Sprintf("   Description: %s\\n", r.Description))\n\t\t}\n\t\trepoList.WriteString("\\n")\n\t}\n\n\t// Build weighting guidance based on available information\n\tweightingGuidance := ""\n\tif hasDefinitions {\n\t\tweightingGuidance = `\nDecision-Making Framework:\n- Primary consideration (~60% weight): Match the issue against repository documentation\n  to understand what each repo is responsible for and what problems it solves\n- Secondary consideration (~40% weight): Consider any historical patterns or precedents\n  from similar issues, if available\n- The repository documentation provides the authoritative definition of what belongs where\n- When documentation clearly indicates a match, prioritize it over other signals`\n\t} else {\n\t\tweightingGuidance = `\nNote: Limited repository documentation available. Base routing primarily on repository descriptions.`\n\t}\n\n\t// Add current repo context if provided\n\tcurrentRepoGuidance := ""\n\tif input.CurrentRepo != "" {\n\t\tcurrentRepoGuidance = fmt.Sprintf(`\nIMPORTANT - Current Repository Context:\n- This issue was created in: %s\n- Default assumption: Issues should STAY in their current repository unless there is CLEAR evidence they belong elsewhere\n- Only recommend transfer if you are CONFIDENT (>= 0.7) the issue truly belongs in a different repository\n- When in doubt, keep the issue in its current repository\n`, input.CurrentRepo)\n\t}\n\n\treturn fmt.Sprintf(`You are an AI assistant helping route GitHub issues to the correct repository.\n\nIssue Details:\n- Title: %s\n- Body: %s\n%s\nAvailable Repositories:\n%s\n%s\n\nTask: Analyze the issue content and rank ALL repositories by relevance.\n\nFor each repository, provide:\n- Confidence score (0.0-1.0) indicating how well the issue matches the repository\n- Brief reasoning explaining your score\n\nRespond with valid JSON in this exact format:\n{\n  "rankings": [\n    {\n      "org": "org-name",\n      "repo": "repo-name",\n      "confidence": 0.85,\n      "reasoning": "Issue describes API authentication errors. The backend repository\'s documentation indicates it handles the authentication service and API layer."\n    }\n  ]\n}\n\nConfidence Score Guidelines:\n- 0.9+ = Very strong match (issue clearly aligns with repo\'s documented responsibilities)\n- 0.7-0.9 = Strong match (issue has significant alignment with repo\'s purpose)\n- 0.5-0.7 = Moderate match (some alignment but not definitive)\n- <0.5 = Weak or no match (little to no alignment with repo\'s documented purpose)\n\nImportant: Include ALL repositories in your rankings, even those with low confidence scores.`,\n\t\tinput.Issue.Title,\n\t\ttruncate(input.Issue.Body, 1000),\n\t\tcurrentRepoGuidance,\n\t\trepoList.String(),\n\t\tweightingGuidance,\n\t)\n}\n\n// buildQualityAssessmentPrompt creates a prompt for issue quality analysis.\nfunc buildQualityAssessmentPrompt(issue *IssueInput) string {\n\treturn fmt.Sprintf(`You are an AI assistant evaluating GitHub issue quality.\n\nIssue Details:\n- Title: %s\n- Body: %s\n- Author: %s\n\nAssess the issue quality based on:\n1. Clarity: Is the problem/request clearly described?\n2. Completeness: Are there reproduction steps (for bugs) or requirements (for features)?\n3. Context: Is there enough background information?\n4. Actionability: Can a developer act on this?\n\nRespond with valid JSON in this exact format:\n{\n  "score": 0.85,\n  "assessment": "good",\n  "issues": ["Missing error logs", "No environment details"],\n  "suggestions": ["Add error messages", "Specify OS and version"],\n  "reasoning": "Issue has clear reproduction steps but lacks error logs and environment details"\n}\n\nScore scale:\n- 0.9-1.0 = excellent (complete, clear, actionable)\n- 0.7-0.9 = good (mostly complete, minor improvements needed)\n- 0.4-0.7 = needs-improvement (missing key information)\n- 0.0-0.4 = poor (unclear or severely incomplete)\n\nAssessment must be one of: "excellent", "good", "needs-improvement", "poor"`,\n\t\tissue.Title,\n\t\ttruncate(issue.Body, 1000),\n\t\tissue.Author,\n\t)\n}\n\n// buildDuplicateDetectionPrompt creates a prompt for duplicate detection analysis.\nfunc buildDuplicateDetectionPrompt(input *DuplicateCheckInput) string {\n\tvar similarList strings.Builder\n\tfor i, s := range input.SimilarIssues {\n\t\tbody := truncate(s.Body, 500)\n\t\tfmt.Fprintf(&similarList, "--- Similar Issue %d ---\\n", i+1)\n\t\tfmt.Fprintf(&similarList, "Issue #%d [%s]: %s\\nVector similarity: %.0f%%\\n",\n\t\t\ts.Number, s.State, s.Title, s.Similarity*100)\n\t\tif body != "" {\n\t\t\tfmt.Fprintf(&similarList, "Content:\\n%s\\n", body)\n\t\t}\n\t\tsimilarList.WriteString("\\n")\n\t}\n\n\treturn fmt.Sprintf(`You are a precise duplicate detection system for GitHub issues.\n\nCRITICAL DISTINCTION:\n- DUPLICATE: Two issues describe the EXACT SAME bug or feature request. Fixing one FULLY resolves the other. They must have the same root cause AND the same expected outcome.\n- RELATED: Two issues are in the same area or component but describe DIFFERENT problems. They may share keywords or affect the same module, but have different root causes or expected outcomes.\n\nBeing related is NOT enough to be a duplicate. Most issues in the same project will be related.\n\nCurrent Issue:\n- Title: %s\n- Body: %s\n\nSimilar Issues Found (by vector similarity — high similarity does NOT mean duplicate):\n%s\n\nCompare the FULL CONTENT of the current issue against each similar issue. Look for:\n1. Same root cause — not just same component or area\n2. Same expected outcome — not just similar symptoms\n3. Would a single fix resolve BOTH issues completely?\n\nIf two issues affect the same module but describe different failure modes, different inputs, or different expected behaviors, they are RELATED, not duplicates.\n\nRespond with valid JSON:\n{\n  "is_duplicate": false,\n  "duplicate_of": 0,\n  "confidence": 0.0,\n  "reasoning": "Brief explanation",\n  "similar_issues": []\n}\n\nConfidence scale (be strict):\n- 0.95+ = Certain duplicate (identical problem, identical root cause)\n- 0.85-0.95 = Very likely duplicate (same root cause, same expected fix)\n- 0.70-0.85 = Related but likely distinct issues\n- <0.70 = Different issues\n\nONLY set is_duplicate to true if confidence >= 0.85. When in doubt, set is_duplicate to false.`,\n\t\tinput.CurrentIssue.Title,\n\t\ttruncate(input.CurrentIssue.Body, 1000),\n\t\tsimilarList.String(),\n\t)\n}\n',
            'internal/integrations/qdrant/client.go': '// Author: Kaviru Hapuarachchi\n// GitHub: https://github.com/Kavirubc\n// Created: 2026-02-02\n// Last Modified: 2026-02-02\n\npackage qdrant\n\nimport (\n\t"context"\n\t"fmt"\n\t"strings"\n\t"time"\n\n\tpb "github.com/qdrant/go-client/qdrant"\n\t"google.golang.org/grpc"\n\t"google.golang.org/grpc/credentials"\n\t"google.golang.org/grpc/credentials/insecure"\n\t"google.golang.org/grpc/metadata"\n)\n\n// Client implements the VectorStore interface for Qdrant.\ntype Client struct {\n\tconn        *grpc.ClientConn\n\tcollections pb.CollectionsClient\n\tpoints      pb.PointsClient\n\tapiKey      string\n\ttimeout     time.Duration\n}\n\n// NewClient creates a new Qdrant client.\n// URL can be in formats: "localhost:6334", "host:port", "https://cloud.qdrant.io:6334"\n// TLS is automatically enabled for URLs containing "https://" or cloud-like domains.\nfunc NewClient(url, apiKey string) (*Client, error) {\n\t// Determine target and TLS requirement\n\ttarget := url\n\tuseTLS := false\n\n\t// Strip protocol if present and determine TLS\n\tif strings.HasPrefix(url, "https://") {\n\t\ttarget = strings.TrimPrefix(url, "https://")\n\t\tuseTLS = true\n\t} else if strings.HasPrefix(url, "http://") {\n\t\ttarget = strings.TrimPrefix(url, "http://")\n\t\tuseTLS = false\n\t} else {\n\t\t// No explicit protocol - check for cloud indicators\n\t\tuseTLS = strings.Contains(strings.ToLower(url), "cloud") ||\n\t\t\tstrings.Contains(strings.ToLower(url), ".qdrant.io")\n\t}\n\n\t// Create gRPC connection with appropriate credentials\n\tvar opts []grpc.DialOption\n\tif useTLS {\n\t\topts = []grpc.DialOption{\n\t\t\tgrpc.WithTransportCredentials(credentials.NewTLS(nil)),\n\t\t}\n\t} else {\n\t\topts = []grpc.DialOption{\n\t\t\tgrpc.WithTransportCredentials(insecure.NewCredentials()),\n\t\t}\n\t}\n\n\tconn, err := grpc.NewClient(target, opts...)\n\tif err != nil {\n\t\treturn nil, fmt.Errorf("failed to connect to Qdrant: %w", err)\n\t}\n\n\treturn &Client{\n\t\tconn:        conn,\n\t\tcollections: pb.NewCollectionsClient(conn),\n\t\tpoints:      pb.NewPointsClient(conn),\n\t\tapiKey:      apiKey,\n\t\ttimeout:     30 * time.Second,\n\t}, nil\n}\n\n// Close closes the gRPC connection.\nfunc (c *Client) Close() error {\n\treturn c.conn.Close()\n}\n\n// ctxWithAuth adds authentication to an existing context with timeout.\nfunc (c *Client) ctxWithAuth(parent context.Context) (context.Context, context.CancelFunc) {\n\tctx, cancel := context.WithTimeout(parent, c.timeout)\n\tif c.apiKey != "" {\n\t\tctx = metadata.AppendToOutgoingContext(ctx, "api-key", c.apiKey)\n\t}\n\treturn ctx, cancel\n}\n\n// CreateCollection creates a new collection if it doesn\'t exist.\nfunc (c *Client) CreateCollection(ctx context.Context, name string, dimension int) error {\n\tauthCtx, cancel := c.ctxWithAuth(ctx)\n\tdefer cancel()\n\n\t// Check if exists first\n\texists, err := c.CollectionExists(ctx, name)\n\tif err != nil {\n\t\treturn err\n\t}\n\tif exists {\n\t\treturn nil\n\t}\n\n\t// Create collection\n\t_, err = c.collections.Create(authCtx, &pb.CreateCollection{\n\t\tCollectionName: name,\n\t\tVectorsConfig: &pb.VectorsConfig{\n\t\t\tConfig: &pb.VectorsConfig_Params{\n\t\t\t\tParams: &pb.VectorParams{\n\t\t\t\t\tSize:     uint64(dimension),\n\t\t\t\t\tDistance: pb.Distance_Cosine,\n\t\t\t\t},\n\t\t\t},\n\t\t},\n\t})\n\tif err != nil {\n\t\treturn fmt.Errorf("failed to create collection: %w", err)\n\t}\n\n\treturn nil\n}\n\n// CollectionExists checks if a collection exists.\nfunc (c *Client) CollectionExists(ctx context.Context, name string) (bool, error) {\n\tauthCtx, cancel := c.ctxWithAuth(ctx)\n\tdefer cancel()\n\n\tresp, err := c.collections.List(authCtx, &pb.ListCollectionsRequest{})\n\tif err != nil {\n\t\treturn false, fmt.Errorf("failed to list collections: %w", err)\n\t}\n\n\tfor _, col := range resp.Collections {\n\t\tif col.Name == name {\n\t\t\treturn true, nil\n\t\t}\n\t}\n\n\treturn false, nil\n}\n\n// Upsert inserts or updates points in the collection.\nfunc (c *Client) Upsert(ctx context.Context, collectionName string, points []*Point) error {\n\tauthCtx, cancel := c.ctxWithAuth(ctx)\n\tdefer cancel()\n\n\tqPoints := make([]*pb.PointStruct, len(points))\n\tfor i, p := range points {\n\t\t// Convert payload map to Qdrant struct\n\t\tpayload := make(map[string]*pb.Value)\n\t\tfor k, v := range p.Payload {\n\t\t\tpayload[k] = toQdrantValue(v)\n\t\t}\n\n\t\t// Parse UUID string to PointId\n\t\tpointID := &pb.PointId{\n\t\t\tPointIdOptions: &pb.PointId_Uuid{\n\t\t\t\tUuid: p.ID,\n\t\t\t},\n\t\t}\n\n\t\tqPoints[i] = &pb.PointStruct{\n\t\t\tId:      pointID,\n\t\t\tVectors: &pb.Vectors{VectorsOptions: &pb.Vectors_Vector{Vector: &pb.Vector{Data: p.Vector}}},\n\t\t\tPayload: payload,\n\t\t}\n\t}\n\n\t_, err := c.points.Upsert(authCtx, &pb.UpsertPoints{\n\t\tCollectionName: collectionName,\n\t\tPoints:         qPoints,\n\t})\n\tif err != nil {\n\t\treturn fmt.Errorf("failed to upsert points: %w", err)\n\t}\n\n\treturn nil\n}\n\n// Search finds the nearest neighbors for a given vector.\nfunc (c *Client) Search(ctx context.Context, collectionName string, vector []float32, limit int, threshold float64) ([]*SearchResult, error) {\n\tauthCtx, cancel := c.ctxWithAuth(ctx)\n\tdefer cancel()\n\n\tscoreThreshold := float32(threshold)\n\tresp, err := c.points.Search(authCtx, &pb.SearchPoints{\n\t\tCollectionName: collectionName,\n\t\tVector:         vector,\n\t\tLimit:          uint64(limit),\n\t\tScoreThreshold: &scoreThreshold,\n\t\tWithPayload:    &pb.WithPayloadSelector{SelectorOptions: &pb.WithPayloadSelector_Enable{Enable: true}},\n\t})\n\tif err != nil {\n\t\treturn nil, fmt.Errorf("failed to search: %w", err)\n\t}\n\n\tresults := make([]*SearchResult, len(resp.Result))\n\tfor i, hit := range resp.Result {\n\t\t// Convert payload back to map\n\t\tpayload := make(map[string]interface{})\n\t\tfor k, v := range hit.Payload {\n\t\t\tpayload[k] = fromQdrantValue(v)\n\t\t}\n\n\t\tid := ""\n\t\tif hit.Id.GetUuid() != "" {\n\t\t\tid = hit.Id.GetUuid()\n\t\t} else {\n\t\t\tid = fmt.Sprintf("%d", hit.Id.GetNum())\n\t\t}\n\n\t\tresults[i] = &SearchResult{\n\t\t\tID:      id,\n\t\t\tScore:   hit.Score,\n\t\t\tPayload: payload,\n\t\t}\n\t}\n\n\treturn results, nil\n}\n\n// Delete removes a point by ID.\nfunc (c *Client) Delete(ctx context.Context, collectionName string, id string) error {\n\tauthCtx, cancel := c.ctxWithAuth(ctx)\n\tdefer cancel()\n\n\t// Handle UUID vs Num ID logic if needed, simplify for now assuming UUID\n\tpointID := &pb.PointId{\n\t\tPointIdOptions: &pb.PointId_Uuid{\n\t\t\tUuid: id,\n\t\t},\n\t}\n\n\t_, err := c.points.Delete(authCtx, &pb.DeletePoints{\n\t\tCollectionName: collectionName,\n\t\tPoints: &pb.PointsSelector{\n\t\t\tPointsSelectorOneOf: &pb.PointsSelector_Points{\n\t\t\t\tPoints: &pb.PointsIdsList{\n\t\t\t\t\tIds: []*pb.PointId{pointID},\n\t\t\t\t},\n\t\t\t},\n\t\t},\n\t})\n\tif err != nil {\n\t\treturn fmt.Errorf("failed to delete point: %w", err)\n\t}\n\n\treturn nil\n}\n\n// Helper to convert Go value to Qdrant Value\nfunc toQdrantValue(v interface{}) *pb.Value {\n\tswitch val := v.(type) {\n\tcase string:\n\t\treturn &pb.Value{Kind: &pb.Value_StringValue{StringValue: val}}\n\tcase int:\n\t\treturn &pb.Value{Kind: &pb.Value_IntegerValue{IntegerValue: int64(val)}}\n\tcase int64:\n\t\treturn &pb.Value{Kind: &pb.Value_IntegerValue{IntegerValue: val}}\n\tcase float64:\n\t\treturn &pb.Value{Kind: &pb.Value_DoubleValue{DoubleValue: val}}\n\tcase bool:\n\t\treturn &pb.Value{Kind: &pb.Value_BoolValue{BoolValue: val}}\n\tdefault:\n\t\treturn &pb.Value{Kind: &pb.Value_StringValue{StringValue: fmt.Sprintf("%v", val)}}\n\t}\n}\n\n// Helper to convert Qdrant Value to Go value\nfunc fromQdrantValue(v *pb.Value) interface{} {\n\tswitch k := v.Kind.(type) {\n\tcase *pb.Value_StringValue:\n\t\treturn k.StringValue\n\tcase *pb.Value_IntegerValue:\n\t\treturn k.IntegerValue\n\tcase *pb.Value_DoubleValue:\n\t\treturn k.DoubleValue\n\tcase *pb.Value_BoolValue:\n\t\treturn k.BoolValue\n\tdefault:\n\t\treturn nil\n\t}\n}\n',
            'internal/integrations/qdrant/types.go': '// Author: Kaviru Hapuarachchi\n// GitHub: https://github.com/Kavirubc\n// Created: 2026-02-02\n// Last Modified: 2026-02-02\n\n// Package qdrant provides the vector database integration.\npackage qdrant\n\nimport "context"\n\n// Point represents a data point in the vector database.\ntype Point struct {\n\tID      string                 `json:"id"`\n\tVector  []float32              `json:"vector"`\n\tPayload map[string]interface{} `json:"payload"`\n}\n\n// SearchResult represents a single result from a similarity search.\ntype SearchResult struct {\n\tID      string                 `json:"id"`\n\tScore   float32                `json:"score"`\n\tPayload map[string]interface{} `json:"payload"`\n\tVector  []float32              `json:"vector,omitempty"`\n}\n\n// VectorStore defines the interface for vector database operations.\ntype VectorStore interface {\n\t// CreateCollection creates a new collection if it doesn\'t exist.\n\tCreateCollection(ctx context.Context, name string, dimension int) error\n\n\t// CollectionExists checks if a collection exists.\n\tCollectionExists(ctx context.Context, name string) (bool, error)\n\n\t// Upsert inserts or updates points in the collection.\n\tUpsert(ctx context.Context, collectionName string, points []*Point) error\n\n\t// Search finds the nearest neighbors for a given vector.\n\tSearch(ctx context.Context, collectionName string, vector []float32, limit int, threshold float64) ([]*SearchResult, error)\n\n\t// Delete removes a point by ID.\n\tDelete(ctx context.Context, collectionName string, id string) error\n\n\t// Close closes the connection to the database.\n\tClose() error\n}\n',
            'internal/steps/indexer.go': '// Author: Kaviru Hapuarachchi\n// GitHub: https://github.com/Kavirubc\n// Created: 2026-02-02\n// Last Modified: 2026-02-13\n\n// Package steps provides the indexer step for adding issues to the vector database.\npackage steps\n\nimport (\n\t"fmt"\n\t"log"\n\t"strings"\n\n\t"github.com/google/go-github/v60/github"\n\t"github.com/google/uuid"\n\t"github.com/similigh/simili-bot/internal/core/pipeline"\n\t"github.com/similigh/simili-bot/internal/integrations/gemini"\n\tsimiliGithub "github.com/similigh/simili-bot/internal/integrations/github"\n\t"github.com/similigh/simili-bot/internal/integrations/qdrant"\n\t"github.com/similigh/simili-bot/internal/utils/text"\n)\n\n// Indexer adds/updates the issue in the vector database.\ntype Indexer struct {\n\tembedder *gemini.Embedder\n\tstore    qdrant.VectorStore\n\tgithub   *similiGithub.Client\n\tdryRun   bool\n}\n\n// NewIndexer creates a new indexer step.\nfunc NewIndexer(deps *pipeline.Dependencies) *Indexer {\n\treturn &Indexer{\n\t\tembedder: deps.Embedder,\n\t\tstore:    deps.VectorStore,\n\t\tgithub:   deps.GitHub,\n\t\tdryRun:   deps.DryRun,\n\t}\n}\n\n// Name returns the step name.\nfunc (s *Indexer) Name() string {\n\treturn "indexer"\n}\n\n// Run adds the issue to the vector database.\nfunc (s *Indexer) Run(ctx *pipeline.Context) error {\n\tcollectionName := ctx.Config.Qdrant.Collection\n\n\t// Skip indexing if the issue was transferred to another repository\n\tif ctx.Result.Transferred {\n\t\tlog.Printf("[indexer] Issue transferred to %s, skipping indexing in source repo", ctx.Result.TransferTarget)\n\t\treturn nil\n\t}\n\n\tif s.dryRun {\n\t\tlog.Printf("[indexer] DRY RUN: Would index issue #%d into %s", ctx.Issue.Number, collectionName)\n\t\treturn nil\n\t}\n\n\tif s.embedder == nil || s.store == nil {\n\t\tlog.Printf("[indexer] WARNING: Missing dependencies, skipping indexing")\n\t\treturn nil\n\t}\n\n\t// Fetch all comment pages for richer embedding content.\n\tvar textComments []text.Comment\n\tif s.github != nil {\n\t\tpage := 1\n\t\tfor {\n\t\t\tghComments, resp, err := s.github.ListComments(ctx.Ctx, ctx.Issue.Org, ctx.Issue.Repo, ctx.Issue.Number, &github.IssueListCommentsOptions{\n\t\t\t\tListOptions: github.ListOptions{PerPage: 100, Page: page},\n\t\t\t})\n\t\t\tif err != nil {\n\t\t\t\tlog.Printf("[indexer] WARNING: failed to fetch comments for #%d: %v", ctx.Issue.Number, err)\n\t\t\t\tbreak\n\t\t\t}\n\t\t\tfor _, c := range ghComments {\n\t\t\t\tauthor := "deleted-user"\n\t\t\t\tif c.User != nil {\n\t\t\t\t\tauthor = c.User.GetLogin()\n\t\t\t\t}\n\t\t\t\ttextComments = append(textComments, text.Comment{Author: author, Body: strings.TrimSpace(c.GetBody())})\n\t\t\t}\n\t\t\tif resp == nil || resp.NextPage == 0 {\n\t\t\t\tbreak\n\t\t\t}\n\t\t\tpage = resp.NextPage\n\t\t}\n\t}\n\n\t// Create content for embedding\n\tcontent := text.BuildEmbeddingContent(ctx.Issue.Title, ctx.Issue.Body, textComments)\n\n\t// Generate embedding\n\tembedding, err := s.embedder.Embed(ctx.Ctx, content)\n\tif err != nil {\n\t\treturn fmt.Errorf("failed to generate embedding: %w", err)\n\t}\n\n\t// Resolve canonical item type for downstream consumers.\n\titemType := "issue"\n\tif ctx.Issue.EventType == "pull_request" || ctx.Issue.EventType == "pr_comment" {\n\t\titemType = "pull_request"\n\t}\n\n\t// Generate deterministic UUID\n\tuniqueID := fmt.Sprintf("%s-%s-%d", ctx.Issue.Org, ctx.Issue.Repo, ctx.Issue.Number)\n\tuuidID := uuid.NewMD5(uuid.NameSpaceURL, []byte(uniqueID)).String()\n\n\t// Prepare point for Qdrant\n\tpoint := &qdrant.Point{\n\t\tID:     uuidID,\n\t\tVector: embedding,\n\t\tPayload: map[string]any{\n\t\t\t"org":    ctx.Issue.Org,\n\t\t\t"repo":   ctx.Issue.Repo,\n\t\t\t"number": ctx.Issue.Number,\n\t\t\t"title":  ctx.Issue.Title,\n\t\t\t"url":    ctx.Issue.URL,\n\t\t\t"state":  ctx.Issue.State,\n\t\t\t"author": ctx.Issue.Author,\n\t\t\t"labels": ctx.Issue.Labels,\n\t\t\t"type":   itemType,\n\t\t},\n\t}\n\n\t// Upsert to Qdrant\n\terr = s.store.Upsert(ctx.Ctx, collectionName, []*qdrant.Point{point})\n\tif err != nil {\n\t\treturn fmt.Errorf("failed to index issue: %w", err)\n\t}\n\n\tlog.Printf("[indexer] Indexed issue #%d to %s", ctx.Issue.Number, collectionName)\n\tctx.Result.Indexed = true\n\n\treturn nil\n}\n',
            'internal/steps/response_builder.go': '// Author: Kaviru Hapuarachchi\n// GitHub: https://github.com/kavirubc\n// Created: 2026-02-02\n// Last Modified: 2026-02-04\n\n// Package steps provides the response builder step.\npackage steps\n\nimport (\n\t"fmt"\n\t"log"\n\t"strings"\n\n\t"github.com/similigh/simili-bot/internal/core/pipeline"\n\t"github.com/similigh/simili-bot/internal/integrations/gemini"\n)\n\n// ResponseBuilder constructs the comment to post on the issue.\ntype ResponseBuilder struct {\n\tllm *gemini.LLMClient\n}\n\n// NewResponseBuilder creates a new response builder step.\nfunc NewResponseBuilder(deps *pipeline.Dependencies) *ResponseBuilder {\n\treturn &ResponseBuilder{\n\t\tllm: deps.LLMClient,\n\t}\n}\n\n// Name returns the step name.\nfunc (s *ResponseBuilder) Name() string {\n\treturn "response_builder"\n}\n\n// Run builds the comprehensive triage summary comment.\nfunc (s *ResponseBuilder) Run(ctx *pipeline.Context) error {\n\t// Skip if it\'s an issue_comment and no comment has been generated by a previous step (like CommandHandler)\n\tif ctx.Issue.EventType == "issue_comment" && ctx.Metadata["comment"] == nil {\n\t\treturn nil\n\t}\n\tlog.Printf("[response_builder] Building comprehensive triage summary for issue #%d", ctx.Issue.Number)\n\n\tcomment := s.buildTriageSummary(ctx)\n\tctx.Metadata["comment"] = comment\n\n\tlog.Printf("[response_builder] Built triage summary")\n\treturn nil\n}\n\n// buildTriageSummary creates a comprehensive triage report.\nfunc (s *ResponseBuilder) buildTriageSummary(ctx *pipeline.Context) string {\n\tvar sections []string\n\n\t// Header\n\tsections = append(sections, "### Simili Triage Report\\n")\n\n\t// Quality Assessment Section\n\tif qualitySection := s.buildQualitySection(ctx); qualitySection != "" {\n\t\tsections = append(sections, qualitySection)\n\t}\n\n\t// Classification Header\n\tsections = append(sections, "#### Classification")\n\t// Start Classification Table\n\tsections = append(sections, "| Category | Value |")\n\tsections = append(sections, "| :--- | :--- |")\n\n\t// Labels Row\n\tif labelsRow := s.buildLabelsRow(ctx); labelsRow != "" {\n\t\tsections = append(sections, labelsRow)\n\t}\n\n\t// Transfer Row\n\tif transferRow := s.buildTransferRow(ctx); transferRow != "" {\n\t\tsections = append(sections, transferRow)\n\t}\n\n\tsections = append(sections, "") // Spacing\n\n\t// Quality Improvements (Collapsible)\n\tif improvements := s.buildQualityImprovements(ctx); improvements != "" {\n\t\tsections = append(sections, improvements)\n\t}\n\n\t// Similar Issues (Collapsible)\n\tif similarSection := s.buildSimilarSection(ctx); similarSection != "" {\n\t\tsections = append(sections, similarSection)\n\t}\n\n\t// Possible Duplicate (Alert)\n\tif duplicateSection := s.buildDuplicateSection(ctx); duplicateSection != "" {\n\t\tsections = append(sections, duplicateSection)\n\t}\n\n\t// Footer\n\tsections = append(sections, "---\\n<sub>Generated by [Simili Bot](https://github.com/similigh/simili-bot)</sub>")\n\n\treturn strings.Join(sections, "\\n")\n}\n\n// buildQualitySection creates the quality assessment section using GitHub Alerts.\nfunc (s *ResponseBuilder) buildQualitySection(ctx *pipeline.Context) string {\n\tqualityResult, ok := ctx.Metadata["quality_result"].(*gemini.QualityResult)\n\tif !ok || qualityResult == nil {\n\t\treturn ""\n\t}\n\n\tvar parts []string\n\n\t// Determine alert type based on score\n\talertType := "NOTE"\n\tif qualityResult.Score < 0.5 {\n\t\talertType = "TIP" // Using TIP for constructive feedback on low quality\n\t}\n\n\tparts = append(parts, fmt.Sprintf("> [!%s]", alertType))\n\n\tassessment := capitalizeFirst(qualityResult.Assessment)\n\tparts = append(parts, fmt.Sprintf("> **Quality Score: %.1f/10 (%s)**", qualityResult.Score*10, assessment))\n\n\tif len(qualityResult.Issues) == 0 {\n\t\tparts = append(parts, "> The issue is well-described.")\n\t} else {\n\t\tparts = append(parts, "> The issue could be improved. See suggestions below.")\n\t}\n\n\tparts = append(parts, "")\n\treturn strings.Join(parts, "\\n")\n}\n\n// buildLabelsRow creates the labels row for the classification table.\nfunc (s *ResponseBuilder) buildLabelsRow(ctx *pipeline.Context) string {\n\tif len(ctx.Result.SuggestedLabels) == 0 {\n\t\treturn "| **Labels** | None |"\n\t}\n\n\tvar badges []string\n\tfor _, label := range ctx.Result.SuggestedLabels {\n\t\t// Heuristic: \'urgent\' or \'bug\' gets orange, others get black\n\t\tcolor := "000000" // Black\n\t\tif strings.Contains(strings.ToLower(label), "urgent") || strings.Contains(strings.ToLower(label), "high") || strings.Contains(strings.ToLower(label), "bug") {\n\t\t\tcolor = "ff7300" // Orange\n\t\t}\n\t\t// URL encode label for Shields.io\n\t\t// Shields.io escaping: underscores -> __, hyphens -> --, spaces -> %20\n\t\tencodedLabel := strings.ReplaceAll(label, "_", "__")\n\t\tencodedLabel = strings.ReplaceAll(encodedLabel, "-", "--")\n\t\tencodedLabel = strings.ReplaceAll(encodedLabel, " ", "%20")\n\t\tbadges = append(badges, fmt.Sprintf("![](https://img.shields.io/badge/%s-%s)", encodedLabel, color))\n\t}\n\n\treturn fmt.Sprintf("| **Labels** | %s |", strings.Join(badges, " "))\n}\n\n// buildTransferRow creates the transfer row for the classification table.\nfunc (s *ResponseBuilder) buildTransferRow(ctx *pipeline.Context) string {\n\trouterResult, ok := ctx.Metadata["router_result"].(*gemini.RouterResult)\n\tif !ok || routerResult == nil || routerResult.BestMatch == nil {\n\t\treturn ""\n\t}\n\n\tmatch := routerResult.BestMatch\n\tconfidence := match.Confidence\n\n\t// Only show if medium or high confidence\n\tif confidence < ctx.Config.Transfer.MediumConfidence {\n\t\treturn ""\n\t}\n\n\ttargetRepo := fmt.Sprintf("%s/%s", match.Org, match.Repo)\n\tconfidencePct := int(confidence * 100)\n\n\tsourceRepo, _ := ctx.Metadata["original_repo"].(string)\n\n\tvar value string\n\t// Black for text, Orange for confidence badge\n\tconfBadge := fmt.Sprintf("![](https://img.shields.io/badge/confidence-%d%%25-ff7300)", confidencePct)\n\n\tif sourceRepo != "" {\n\t\t// Actually transferred from another repo\n\t\tvalue = fmt.Sprintf("🔄 Transferred from **%s** %s", sourceRepo, confBadge)\n\t} else if targetRepo == fmt.Sprintf("%s/%s", ctx.Issue.Org, ctx.Issue.Repo) {\n\t\t// Best match is current repo\n\t\tvalue = fmt.Sprintf("✅ Belongs in **%s** %s", targetRepo, confBadge)\n\t} else {\n\t\t// Suggestion\n\t\tvalue = fmt.Sprintf("Suggested: **%s** %s", targetRepo, confBadge)\n\t}\n\n\treturn fmt.Sprintf("| **Transfer** | %s |", value)\n}\n\n// buildQualityImprovements creates the collapsible quality suggestions section.\nfunc (s *ResponseBuilder) buildQualityImprovements(ctx *pipeline.Context) string {\n\tqualityResult, ok := ctx.Metadata["quality_result"].(*gemini.QualityResult)\n\tif !ok || qualityResult == nil {\n\t\treturn ""\n\t}\n\n\t// Combine issues and suggestions\n\tvar items []string\n\titems = append(items, qualityResult.Issues...)\n\titems = append(items, qualityResult.Suggestions...)\n\n\tif len(items) == 0 {\n\t\treturn ""\n\t}\n\n\tvar parts []string\n\tparts = append(parts, "<details>")\n\tparts = append(parts, "<summary>Quality Improvements</summary>")\n\tparts = append(parts, "")\n\n\tfor _, item := range items {\n\t\tparts = append(parts, fmt.Sprintf("- %s", item))\n\t}\n\n\tparts = append(parts, "</details>")\n\tparts = append(parts, "")\n\treturn strings.Join(parts, "\\n")\n}\n\n// buildSimilarSection creates the similar issues section.\nfunc (s *ResponseBuilder) buildSimilarSection(ctx *pipeline.Context) string {\n\tif len(ctx.SimilarIssues) == 0 {\n\t\treturn ""\n\t}\n\n\tvar parts []string\n\tparts = append(parts, "<details>")\n\tparts = append(parts, "<summary>Similar Threads</summary>")\n\tparts = append(parts, "")\n\tparts = append(parts, "| Similarity | Thread | Status |")\n\tparts = append(parts, "| :--- | :--- | :--- |")\n\n\tfor _, similar := range ctx.SimilarIssues {\n\t\tstatus := "Open"\n\t\tif similar.State == "closed" {\n\t\t\tstatus = "Closed"\n\t\t}\n\n\t\t// Truncate title if too long (UTF-8 safe)\n\t\ttitle := similar.Title\n\t\trunes := []rune(title)\n\t\tif len(runes) > 50 {\n\t\t\ttitle = string(runes[:47]) + "..."\n\t\t}\n\n\t\tparts = append(parts, fmt.Sprintf("| %.0f%% | [#%d %s](%s) | %s |",\n\t\t\tsimilar.Similarity*100, similar.Number, title, similar.URL, status))\n\t}\n\n\tparts = append(parts, "</details>")\n\tparts = append(parts, "")\n\treturn strings.Join(parts, "\\n")\n}\n\n// buildDuplicateSection creates the duplicate warning section.\nfunc (s *ResponseBuilder) buildDuplicateSection(ctx *pipeline.Context) string {\n\tduplicateResult, ok := ctx.Metadata["duplicate_result"].(*gemini.DuplicateResult)\n\tif !ok || duplicateResult == nil || !duplicateResult.IsDuplicate {\n\t\treturn ""\n\t}\n\n\tvar parts []string\n\tconfidencePct := int(duplicateResult.Confidence * 100)\n\n\tparts = append(parts, "> [!WARNING]")\n\tparts = append(parts, fmt.Sprintf("> **Possible Duplicate** (Confidence: %d%%)", confidencePct))\n\tsubject := "issue"\n\tif ctx.Issue.EventType == "pull_request" || ctx.Issue.EventType == "pr_comment" {\n\t\tsubject = "pull request"\n\t}\n\tparts = append(parts, fmt.Sprintf("> This %s might be a duplicate of #%d.", subject, duplicateResult.DuplicateOf))\n\n\tif duplicateResult.Reasoning != "" {\n\t\tparts = append(parts, fmt.Sprintf("> _Reason: %s_", duplicateResult.Reasoning))\n\t}\n\n\tparts = append(parts, "")\n\treturn strings.Join(parts, "\\n")\n}\n\n// capitalizeFirst capitalizes the first letter of a string.\nfunc capitalizeFirst(s string) string {\n\tif s == "" {\n\t\treturn s\n\t}\n\treturn strings.ToUpper(s[:1]) + s[1:]\n}\n',
            'internal/steps/similarity.go': '// Author: Kaviru Hapuarachchi\n// GitHub: https://github.com/Kavirubc\n// Created: 2026-02-02\n// Last Modified: 2026-02-02\n\n// Package steps provides the similarity search step.\npackage steps\n\nimport (\n\t"fmt"\n\t"log"\n\t"strings"\n\n\t"github.com/similigh/simili-bot/internal/core/pipeline"\n\t"github.com/similigh/simili-bot/internal/integrations/gemini"\n\t"github.com/similigh/simili-bot/internal/integrations/qdrant"\n)\n\n// SimilaritySearch finds similar issues using the vector database.\ntype SimilaritySearch struct {\n\tembedder *gemini.Embedder\n\tstore    qdrant.VectorStore\n}\n\n// NewSimilaritySearch creates a new similarity search step.\nfunc NewSimilaritySearch(deps *pipeline.Dependencies) *SimilaritySearch {\n\treturn &SimilaritySearch{\n\t\tembedder: deps.Embedder,\n\t\tstore:    deps.VectorStore,\n\t}\n}\n\n// Name returns the step name.\nfunc (s *SimilaritySearch) Name() string {\n\treturn "similarity_search"\n}\n\n// Run searches for similar issues.\nfunc (s *SimilaritySearch) Run(ctx *pipeline.Context) error {\n\t// Skip if transfer is detected (duplicate detection not needed)\n\tif skip, ok := ctx.Metadata["skip_duplicate_detection"].(bool); ok && skip {\n\t\tlog.Printf("[similarity_search] Skipping (transfer detected)")\n\t\treturn nil\n\t}\n\n\tcollectionName := ctx.Config.Qdrant.Collection\n\tthreshold := ctx.Config.Defaults.SimilarityThreshold\n\tlimit := ctx.Config.Defaults.MaxSimilarToShow\n\n\t// Cross-repo search logic could be added here if needed, but current implementation\n\t// depends on the collection containing all org issues.\n\n\t// Skip if dependencies are missing (e.g. testing mode)\n\tif s.embedder == nil || s.store == nil {\n\t\tlog.Printf("[similarity_search] WARNING: Dependencies missing, skipping search")\n\t\treturn nil\n\t}\n\n\t// Create content for embedding\n\tcontent := fmt.Sprintf("%s\\n\\n%s", ctx.Issue.Title, ctx.Issue.Body)\n\n\t// Generate embedding\n\tembedding, err := s.embedder.Embed(ctx.Ctx, content)\n\tif err != nil {\n\t\treturn fmt.Errorf("failed to generate embedding: %w", err)\n\t}\n\n\t// Search in Qdrant\n\tresults, err := s.store.Search(ctx.Ctx, collectionName, embedding, limit, threshold)\n\tif err != nil {\n\t\t// Log error but don\'t fail pipeline? Or fail?\n\t\t// Failing is probably safer so we know somethings wrong.\n\t\treturn fmt.Errorf("failed to search for similar issues: %w", err)\n\t}\n\n\tfoundIssues := make([]pipeline.SimilarIssue, 0, len(results))\n\tfor _, res := range results {\n\t\t// Safely extract payload fields with type checking\n\t\t// Match the indexer which uses "issue_number", and handle multiple numeric types\n\t\tvar number int\n\t\tnumFound := false\n\n\t\tfor _, key := range []string{"number", "issue_number"} {\n\t\t\tif val, ok := res.Payload[key]; ok {\n\t\t\t\tswitch v := val.(type) {\n\t\t\t\tcase float64:\n\t\t\t\t\tnumber = int(v)\n\t\t\t\t\tnumFound = true\n\t\t\t\tcase int64:\n\t\t\t\t\tnumber = int(v)\n\t\t\t\t\tnumFound = true\n\t\t\t\tcase int:\n\t\t\t\t\tnumber = v\n\t\t\t\t\tnumFound = true\n\t\t\t\t}\n\t\t\t}\n\t\t\tif numFound {\n\t\t\t\tbreak\n\t\t\t}\n\t\t}\n\n\t\tif !numFound {\n\t\t\tlog.Printf("[similarity_search] WARNING: No valid issue number in payload, skipping result")\n\t\t\tcontinue\n\t\t}\n\n\t\t// Filter out the current issue itself\n\t\tresRepo, _ := res.Payload["repo"].(string)\n\t\tif number == ctx.Issue.Number && resRepo == ctx.Issue.Repo {\n\t\t\tcontinue\n\t\t}\n\n\t\t// Safely extract other fields, with fallbacks\n\t\ttitle, _ := res.Payload["title"].(string)\n\t\tfullText, _ := res.Payload["text"].(string)\n\n\t\tif title == "" {\n\t\t\t// Try to extract from text if title is missing (indexers often put it there)\n\t\t\tif strings.HasPrefix(fullText, "Title: ") {\n\t\t\t\tlines := strings.SplitN(fullText, "\\n", 2)\n\t\t\t\ttitle = strings.TrimPrefix(lines[0], "Title: ")\n\t\t\t} else {\n\t\t\t\ttitle = "Similar Issue"\n\t\t\t}\n\t\t}\n\n\t\turl, _ := res.Payload["url"].(string)\n\t\tstate, _ := res.Payload["state"].(string)\n\t\tif state == "" {\n\t\t\tstate = "open" // Default\n\t\t}\n\n\t\tissue := pipeline.SimilarIssue{\n\t\t\tNumber:     number,\n\t\t\tTitle:      title,\n\t\t\tBody:       fullText,\n\t\t\tURL:        url,\n\t\t\tState:      state,\n\t\t\tSimilarity: float64(res.Score),\n\t\t}\n\t\tfoundIssues = append(foundIssues, issue)\n\t}\n\n\tctx.SimilarIssues = foundIssues\n\tctx.Result.SimilarFound = foundIssues\n\n\tlog.Printf("[similarity_search] Found %d similar issues for #%d", len(foundIssues), ctx.Issue.Number)\n\n\treturn nil\n}\n',
        }
